import React, { useState } from "react";
import "./App.css";

function App() {
  const [users, setUsers] = useState([
    {
      id: "101",
      name: "Aman Kumar",
      email: "aman@gmail.com",
      contact: "9876543210",
      designation: "Manager",
      company: "ABC Pvt. Ltd.",
      address: "Delhi, India",
    },
  ]);

  const [form, setForm] = useState({
    id: "",
    name: "",
    email: "",
    contact: "",
    designation: "",
    company: "",
    address: "",
  });

  const handleChange = (e) => {
    setForm({ ...form, [e.target.name]: e.target.value });
  };

  const addUser = () => {
    setUsers([...users, form]);
    clearForm();
  };

  const deleteUser = (id) => {
    setUsers(users.filter((user) => user.id !== id));
  };

  const clearForm = () => {
    setForm({
      id: "",
      name: "",
      email: "",
      contact: "",
      designation: "",
      company: "",
      address: "",
    });
  };

  return (
    <div className="main">
      <h1 className="title">USER MANAGEMENT SYSTEM</h1>

      <div className="card">
        <div className="grid">
          <input name="id" placeholder="User ID" value={form.id} onChange={handleChange} />
          <input name="name" placeholder="Name" value={form.name} onChange={handleChange} />
          <input name="email" placeholder="Email" value={form.email} onChange={handleChange} />
          <input name="contact" placeholder="Contact" value={form.contact} onChange={handleChange} />
          <input name="designation" placeholder="Designation" value={form.designation} onChange={handleChange} />
          <input name="company" placeholder="Company" value={form.company} onChange={handleChange} />
          <input name="address" placeholder="Address" value={form.address} onChange={handleChange} />
        </div>

        <div className="buttons">
          <button className="add" onClick={addUser}>+ Add User</button>
          <button className="search">Search by ID</button>
          <button className="clear" onClick={clearForm}>Clear</button>
          <button className="reset">Reset</button>
        </div>
      </div>

      <div className="table-card">
        <h2>Users List</h2>
        <table>
          <thead>
            <tr>
              <th>ID</th>
              <th>Name</th>
              <th>Email</th>
              <th>Contact</th>
              <th>Designation</th>
              <th>Company</th>
              <th>Address</th>
              <th>Action</th>
            </tr>
          </thead>
          <tbody>
            {users.map((user) => (
              <tr key={user.id}>
                <td>{user.id}</td>
                <td>{user.name}</td>
                <td>{user.email}</td>
                <td>{user.contact}</td>
                <td>{user.designation}</td>
                <td>{user.company}</td>
                <td>{user.address}</td>
                <td>
                  <button className="delete" onClick={() => deleteUser(user.id)}>
                    Delete
                  </button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>

        <div className="total">
          Total Users: {users.length}
        </div>
      </div>
    </div>
  );
}

export default App;
